const b = $input.first().json.body || $input.first().json;
if (!b.title) throw new Error('Payload mancante: campo title obbligatorio');
return {
  newsId: b.newsId || b.id || ('news_' + Date.now()),
  title: b.title,
  summary: b.content || b.summary || '',
  source: b.source || 'Unknown',
  link: b.url || b.link || '',
  date: b.date || new Date().toISOString(),
  timestamp: b.timestamp || new Date().toISOString()
};

const res = $input.first().json;
if (!res.success) throw new Error('Generazione fallita: ' + JSON.stringify(res));
const item = res.data && res.data[0];
if (!item) throw new Error('Nessun dato generato');
const payload = item.payload || {};
const posts = payload.generatedPosts || [];
const preview = posts
  .map(p => p.platform.toUpperCase() + '\n' + p.content + '\n' + (p.hashtags || []).join(' '))
  .join('\n\n---\n\n');
return {
  newsId: item.newsId || payload.newsId,
  title: payload.title,
  summary: payload.summary,
  source: payload.source,
  link: payload.link,
  generatedPosts: posts,
  blogPost: payload.blogPostMarkdown || '',
  formattedPreview: preview,
  postCount: posts.length,
  platforms: posts.map(p => p.platform)
};

